#!/bin/bash`n# lib/detect.sh - 硬件检测函数库`n`ndetect_cpu_cores() {`n    nproc 2>/dev/null || grep -c ^processor /proc/cpuinfo || echo "1"`n}`n`ndetect_memory_mb() {`n    free -m 2>/dev/null | awk '/^Mem:/{print int($2)}' || echo "1024"`n}`n`ndetect_memory_gb() {`n    local mb=$(detect_memory_mb)`n    echo "scale=1; $mb / 1024" | bc 2>/dev/null || echo "1"`n}`n`ndetect_disk_gb() {`n    df -BG / 2>/dev/null | awk 'NR==2 {print int($2)}' | tr -d 'G' || echo "10"`n}`n`ndetect_disk_device() {`n    lsblk -no PKNAME "$(df / | tail -1 | awk '{print $1}')" 2>/dev/null || echo "sda"`n}`n`ndetect_disk_total_gb() {`n    local disk=$(detect_disk_device)`n    blockdev --getsize64 "/dev/$disk" 2>/dev/null | \`n        awk '{print int($1/1024/1024/1024)}' || echo "0"`n}`n`ndetect_default_interface() {`n    ip route | grep default | awk '{print $5}' | head -1 || echo "eth0"`n}`n`ndetect_hardware() {`n    cat << EOF`nCPU_CORES=$(detect_cpu_cores)`nMEMORY_MB=$(detect_memory_mb)`nMEMORY_GB=$(detect_memory_gb)`nDISK_GB=$(detect_disk_gb)`nDISK_DEVICE=$(detect_disk_device)`nEOF`n}`n